// Scheduled messages config
// Edit this array to add/remove/modify scheduled messages
// Times are in 24h format, Israel timezone (UTC+2/3)
const now = new Date();
const israelTime = new Date(now.toLocaleString('en-US', { timeZone: 'Asia/Jerusalem' }));
const dayOfWeek = israelTime.getDay(); // 0=Sun, 1=Mon...
const hour = israelTime.getHours();
const minute = israelTime.getMinutes();
const dayName = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'][dayOfWeek];

const scheduledMessages = [
  // === DAILY MESSAGES ===
  {
    id: 'daily-standup-reminder',
    channel: 'REPLACE_CHANNEL_ID',
    text: ':coffee: Good morning team! Time for standup updates.',
    hour: 9,
    minute: 0,
    days: ['Sun','Mon','Tue','Wed','Thu'], // Israeli work week
    enabled: true
  },
  // === WEEKLY MESSAGES ===
  {
    id: 'weekly-it-review',
    channel: 'REPLACE_CHANNEL_ID',
    text: ':clipboard: Weekly IT review — please update your open tickets in JSM before EOD.',
    hour: 10,
    minute: 0,
    days: ['Thu'],
    enabled: true
  },
  {
    id: 'weekly-friday-wrap',
    channel: 'REPLACE_CHANNEL_ID',
    text: ':wave: Shabbat Shalom! Reminder: update your status if OOO next week.',
    hour: 14,
    minute: 0,
    days: ['Fri'],
    enabled: true
  },
  // === MONTHLY MESSAGES (1st of month) ===
  {
    id: 'monthly-license-audit',
    channel: 'REPLACE_CHANNEL_ID',
    text: ':mag: Monthly reminder: review SaaS license usage and deactivate unused accounts.',
    hour: 10,
    minute: 0,
    days: ['Sun','Mon','Tue','Wed','Thu'],
    monthDay: 1, // only on 1st of the month
    enabled: false
  }
];

const toSend = scheduledMessages.filter(msg => {
  if (!msg.enabled) return false;
  if (msg.hour !== hour || msg.minute !== minute) return false;
  if (!msg.days.includes(dayName)) return false;
  if (msg.monthDay && israelTime.getDate() !== msg.monthDay) return false;
  return true;
});

if (toSend.length === 0) {
  return []; // nothing to send this minute
}

return toSend.map(msg => ({ json: { channel: msg.channel, text: msg.text, id: msg.id } }));
